export interface GetOnlineMeeting_Response {
  // The unique identifier of the online meeting
  id?: string;
  // The subject of the online meeting
  subject?: string;
  // The start time of the meeting in UTC
  startDateTime?: string;
  // The end time of the meeting in UTC
  endDateTime?: string;
  // The creation time of the meeting in UTC
  creationDateTime?: string;
  // The URL used to join the meeting online
  joinWebUrl?: string;
  // Settings related to the join meeting ID
  joinMeetingIdSettings?: {
    // The numeric ID used to join the meeting
    joinMeetingId?: string;
    // Indicates whether a passcode is required to join the meeting
    isPasscodeRequired?: boolean;
    // The passcode for joining the meeting
    passcode?: string;
  };
  // The participants of the meeting
  participants?: {
    // The organizer of the meeting
    organizer?: {
      // The user principal name of the organizer
      upn?: string;
      // The identity of the organizer
      identity?: {
        // The user identity of the organizer
        user?: {
          // The unique identifier of the organizer
          id?: string;
          // The display name of the organizer
          displayName?: string;
        };
      };
    };
  };
  // Phone call-in information for the meeting
  audioConferencing?: {
    // The conference ID of the meeting
    conferenceId?: string;
    // The dial-in phone number
    tollNumber?: string;
    // The free toll dial-in phone number
    tollFreeNumber?: string;
    // A URL to the web page with dial-in information
    dialinUrl?: string;
  };
  // Whether announce notifications are enabled for callers joining or leaving the meeting
  isEntryExitAnnounced?: boolean;
  // Specifies who can be a presenter in the meeting
  allowedPresenters?: string;
  // Specifies which participants can bypass the meeting lobby
  lobbyBypassSettings?: {
    // Specifies the type of participants that are automatically admitted into a meeting
    scope?: string;
    // Specifies whether dial-in callers bypass the lobby
    isDialInBypassEnabled?: boolean;
  };
  // Indicates whether to record the meeting automatically
  recordAutomatically?: boolean;
  // Specifies the mode of meeting chat
  allowMeetingChat?: string;
  // A URL for the organizer to change settings for the meeting
  meetingOptionsWebUrl?: string;
}

