export type SectionResponsedisplayIconskinTone = 'light'|'mediumLight'|'medium'|'mediumDark'|'dark';
export type SectionResponsesortType = 'mostRecent'|'unreadThenMostRecent'|'nameAlphabetical'|'userDefinedCustomOrder';
export type SectionResponsesectionType = 'userDefined'|'systemDefined';

export interface SectionResponse {
  // ETag for the sections collection. Pass as If-Match on Create, Update, and Delete.
  "@odata.etag"?: string;
  // The section ID
  id?: string;
  // The display name of the section
  displayName?: string;
  // The display icon for the section
  displayIcon?: {
    // Type of icon. Supported values: emoji Unicode characters or 'custom' for a custom icon.
    iconType?: string;
    // The display name of the icon
    displayName?: string;
    // Skin tone for emoji icons that support skin tone modifiers
    skinTone?: SectionResponsedisplayIconskinTone;
  };
  // Whether the section is expanded
  isExpanded?: boolean;
  // The sort type for the section
  sortType?: SectionResponsesortType;
  // The type of section
  sectionType?: SectionResponsesectionType;
  // The date and time when the section was created
  createdDateTime?: string;
  // The date and time when the section was last modified
  lastModifiedDateTime?: string;
}

export interface ListSectionsResponse {
  "@odata.context"?: string;
  // Version identifier for the sections hierarchy. Pass as If-Match on Create, Update, Delete, Add Item, Remove Item, and Move Item operations.
  _microsoft_graph_sectionsVersion?: string;
  // List of sections
  value?: SectionResponse[];
}

export type SectionItemResponseitemType = 'chat'|'channel'|'meeting'|'community';

export interface SectionItemResponse {
  // ETag for the section items collection. Pass as If-Match on Add, Remove, and Move.
  "@odata.etag"?: string;
  // The unique identifier of the item. Corresponds to the conversation ID of the underlying chat, channel, meeting, or community.
  id?: string;
  // The type of the item
  itemType?: SectionItemResponseitemType;
  // The date and time when the item was added to the section
  createdDateTime?: string;
  // The date and time when the item was last modified
  lastModifiedDateTime?: string;
}

export interface ListSectionItemsResponse {
  "@odata.context"?: string;
  // List of section items
  value?: SectionItemResponse[];
}

export interface SectionItemConflictError {
  error?: {
    code?: string;
    message?: string;
    // The ID of the section that currently holds the item. Use this with Move Section Item to relocate it.
    conflictingSectionId?: string;
    innerError?: {
      // Original Graph error details. The conflictingSectionId entry is also surfaced at error.conflictingSectionId for convenience.
      additionalErrorDetails?: {
       code?: string;
       message?: string;
     }[];
    };
  };
}

